    key_store[free_index].permissions = 0;

    // Compute hash using djb2 algorithm
    unsigned long hash = 5381;
    const char* ptr = api_key;
    while (*ptr != '\0') {
        hash = ((hash << 5) + hash) + (unsigned char)(*ptr); // hash * 33 + current character
        ptr++;
    }

    return hash;
}
